namespace sv_f8c90925f2094cce822cd551948b6865.Services;

public class CartItem
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public decimal Price { get; set; }
    public int Quantity { get; set; }
}

public class CartState
{
    private readonly List<CartItem> _items = [];

    public IReadOnlyList<CartItem> Items => _items;
    public int Count => _items.Sum(i => i.Quantity);
    public decimal Total => _items.Sum(i => i.Price * i.Quantity);

    public event Action? OnChange;

    public void Add(CartItem item)
    {
        var existing = _items.FirstOrDefault(i => i.Id == item.Id);
        if (existing is not null)
        {
            existing.Quantity += item.Quantity;
        }
        else
        {
            _items.Add(new CartItem
            {
                Id = item.Id,
                Name = item.Name,
                Price = item.Price,
                Quantity = item.Quantity
            });
        }
        OnChange?.Invoke();
    }

    public void Remove(int productId)
    {
        var item = _items.FirstOrDefault(i => i.Id == productId);
        if (item is not null)
        {
            _items.Remove(item);
            OnChange?.Invoke();
        }
    }

    public void Clear()
    {
        _items.Clear();
        OnChange?.Invoke();
    }
}

@using sv_f8c90925f2094cce822cd551948b6865.Services
@inject CartState Cart
@implements IDisposable

<a href="cart" class="nav-link cart-badge-link">
    🛒 Cart
    @if (Cart.Count > 0)
    {
        <span class="badge bg-danger rounded-pill ms-1">@Cart.Count</span>
    }
</a>

@code {
    protected override void OnInitialized()
    {
        Cart.OnChange += StateHasChanged;
    }

    public void Dispose()
    {
        Cart.OnChange -= StateHasChanged;
    }
}

@page "/products"
@using sv_f8c90925f2094cce822cd551948b6865.Services
@inject CartState Cart
@rendermode InteractiveServer

<PageTitle>Products</PageTitle>

<h1>Products</h1>

<div class="row row-cols-1 row-cols-md-3 g-4 mt-2">
    @foreach (var product in _products)
    {
        <div class="col">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@product.Name</h5>
                    <p class="card-text text-muted">@product.Price.ToString("C")</p>
                </div>
                <div class="card-footer">
                    <button class="btn btn-primary" @onclick="() => AddToCart(product)">
                        Add to Cart
                    </button>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private readonly List<ProductInfo> _products =
    [
        new(1, "Wireless Headphones", 59.99m),
        new(2, "Mechanical Keyboard", 89.99m),
        new(3, "USB-C Hub", 34.99m),
        new(4, "Webcam HD 1080p", 49.99m),
        new(5, "Laptop Stand", 29.99m),
        new(6, "Mouse Pad XL", 19.99m),
    ];

    private void AddToCart(ProductInfo product)
    {
        Cart.Add(new CartItem
        {
            Id = product.Id,
            Name = product.Name,
            Price = product.Price,
            Quantity = 1
        });
    }

    private record ProductInfo(int Id, string Name, decimal Price);
}

@page "/cart"
@using sv_f8c90925f2094cce822cd551948b6865.Services
@inject CartState Cart
@implements IDisposable
@rendermode InteractiveServer

<PageTitle>Cart</PageTitle>

<h1>Your Cart</h1>

@if (Cart.Items.Count == 0)
{
    <p class="text-muted mt-3">Your cart is empty. <a href="products">Browse products</a></p>
}
else
{
    <table class="table mt-3">
        <thead>
            <tr>
                <th>Product</th>
                <th>Price</th>
                <th>Quantity</th>
                <th>Subtotal</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var item in Cart.Items)
            {
                <tr>
                    <td>@item.Name</td>
                    <td>@item.Price.ToString("C")</td>
                    <td>@item.Quantity</td>
                    <td>@((item.Price * item.Quantity).ToString("C"))</td>
                    <td>
                        <button class="btn btn-sm btn-outline-danger" @onclick="() => Cart.Remove(item.Id)">
                            Remove
                        </button>
                    </td>
                </tr>
            }
        </tbody>
        <tfoot>
            <tr>
                <td colspan="3" class="text-end fw-bold">Total:</td>
                <td class="fw-bold">@Cart.Total.ToString("C")</td>
                <td>
                    <button class="btn btn-sm btn-outline-secondary" @onclick="Cart.Clear">
                        Clear All
                    </button>
                </td>
            </tr>
        </tfoot>
    </table>
}

@code {
    protected override void OnInitialized()
    {
        Cart.OnChange += StateHasChanged;
    }

    public void Dispose()
    {
        Cart.OnChange -= StateHasChanged;
    }
}

